head.script:
(function() {
  const XHTML_NS = "http://www.w3.org/1999/xhtml";
  const root = document.querySelector("foreignObject").firstElementChild;

  Object.defineProperty(document, 'head', { get: function() { return root.querySelector('head'); } });
  Object.defineProperty(document, 'body', { get: function() { return root.querySelector('body'); } });
  Object.defineProperty(document, 'documentElement', { get: function() { return root; } });
})();
